import React from 'react';
import { Card, CardContent, Box, Typography, Stack, LinearProgress } from '@mui/material';
import response from './response.json';

interface GoalData {
  goal: {
    name: string;
    targetAmount: number;
    currentAmount: number;
    percentageComplete: number;
    projectedCompletionDate: string;
  };
}

export default function Widget() {
  const goalData = response.data as GoalData;
  const { goal } = goalData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF4500' }}>
              {goal.name}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Target: ${goal.targetAmount.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Current: ${goal.currentAmount.toLocaleString()}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Projected Completion: {new Date(goal.projectedCompletionDate).toLocaleDateString()}
            </Typography>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between" sx={{ mb: 0.5 }}>
              <Typography variant="caption" color="text.secondary">
                Progress
              </Typography>
              <Typography variant="caption" fontWeight={600} sx={{ color: '#FFD700' }}>
                {goal.percentageComplete}%
              </Typography>
            </Stack>
            <LinearProgress
              variant="determinate"
              value={goal.percentageComplete}
              sx={{
                height: 8,
                borderRadius: 4,
                bgcolor: '#FFEFD5',
                '& .MuiLinearProgress-bar': {
                  bgcolor: '#FFD700',
                  borderRadius: 4,
                }
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
